from pathlib import Path
import re
root=Path('.')
r=root/'assets/app-runtime.js'; css=root/'assets/app.css'; idx=root/'index.html'; loader=root/'assets/app.js'; wf=root/'.github/workflows/static.yml'
old=root/'.github/scripts/apply_recurrence_scope.py'; self=root/'.github/scripts/apply_task_links.py'; wfs=root/'.github/workflows/apply-task-links.yml'
